{
  "allowedTools": [
    "bash(pytest)",
    "bash(make build)"
  ]
}

{
  "mcpServers": {
    "obsidian": {
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-obsidian"],
      "env": {
        "OBSIDIAN_VAULT_PATH": "~/my-vault"
      }
    }
  }
}

{
  "mcpServers": {
    "my-tools": {
      "command": "python",
      "args": ["./tools/server.py"]
    }
  }
}

{
  "mcpServers": {
    "supabase": {
      "command": "npx",
      "args": ["-y", "@supabase/mcp-server"],
      "env": {
        "SUPABASE_URL": "https://your-project.supabase.co",
        "SUPABASE_SERVICE_ROLE_KEY": "your-service-role-key"
      }
    },
    "github": {
      "command": "npx",
      "args": ["-y", "@modelcontextprotocol/server-github"],
      "env": {
        "GITHUB_TOKEN": "ghp_your-token"
      }
    }
  }
}

{
  "hooks": {
    "postTool": [
      {
        "tool": "edit",
        "command": "prettier --write $FILE_PATH"
      }
    ]
  }
}

{
  "hooks": {
    "sessionStart": [
      {
        "command": "./scripts/check-env.sh"
      },
      {
        "command": "git pull --rebase origin main"
      }
    ]
  }
}

{
  "hooks": {
    "postTool": [
      {
        "tool": "edit",
        "command": "[[ $FILE_PATH == *.ts || $FILE_PATH == *.tsx ]] && npx eslint --fix $FILE_PATH || true"
      }
    ]
  }
}

{
  "hooks": {
    "preTool": [
      {
        "tool": "bash",
        "command": "echo $TOOL_INPUT | grep -iqE 'rm -rf|drop table' && echo 'Destructive command blocked' && exit 1 || true"
      }
    ]
  }
}
